import React from 'react';
import {
  MoneyInput,
  NumberInput,
  LabelMoney,
  DS_TEXT_END_CLASS,
} from '@linm-soft-org/linm-web-common-components';
import type { MaterialDto } from '../../services/master/models';
import type { InvoiceLineDto } from '../../services/bh/models';
import { LineMaterialSearchCell, MaterialLineTableHeaders } from '../search/LineMaterialSearchCell';
import { MaterialLinesGridActions } from './MaterialLinesGridActions';
import { InvoiceLineDiscountPair } from './InvoiceLineDiscountPair';
import type { InvoiceLineFieldErrors } from '../../utils/invoiceFieldValidation';
import df from '../../styles/documentForm.module.css';

export type InvoiceLinesGridProps = {
  lines: InvoiceLineDto[];
  canEdit: boolean;
  onChange: (lines: InvoiceLineDto[]) => void;
  patchLine: (idx: number, patch: Partial<InvoiceLineDto>) => void;
  onAddLine: () => void;
  onCopyLine: () => void;
  lineRowProps: (idx: number) => React.HTMLAttributes<HTMLTableRowElement>;
  onRemoveLine: (idx: number) => void;
  /** Per-line field errors (Pattern B) */
  lineErrors?: Record<number, InvoiceLineFieldErrors>;
  /** Per-line field re-validation on change */
  onLineFieldErrorChange?: (rowIdx: number, key: string, value: string | number | undefined, currentMaterialCode?: string) => void;
  testIdPrefix?: string;
};

export const InvoiceLinesGrid: React.FC<InvoiceLinesGridProps> = ({
  lines,
  canEdit,
  onChange,
  patchLine,
  onAddLine,
  onCopyLine,
  lineRowProps,
  onRemoveLine,
  lineErrors,
  onLineFieldErrorChange,
  testIdPrefix = 'hoa-don',
}) => {
  const tid = (suffix: string) => `${testIdPrefix}-${suffix}`;

  const updateLine = (idx: number, patch: Partial<InvoiceLineDto>) => {
    patchLine(idx, patch);
  };

  const handleMaterialSelect = (idx: number, material: MaterialDto) => {
    updateLine(idx, {
      materialCode: material.code,
      materialName: material.name,
      unitCode: material.unitCode || lines[idx]?.unitCode || 'Cai',
    });
    onLineFieldErrorChange?.(idx, 'materialCode', material.code);
  };

  const handleMaterialClear = (idx: number) => {
    updateLine(idx, { materialCode: '', materialName: '' });
    onLineFieldErrorChange?.(idx, 'materialCode', '');
  };

  const makeQuantityChange = (idx: number) => (quantity: number | undefined) => {
    const mc = lines[idx]?.materialCode;
    updateLine(idx, { quantity });
    onLineFieldErrorChange?.(idx, 'quantity', quantity, mc);
  };

  const makeUnitPriceChange = (idx: number) => (unitPrice: number | undefined) => {
    const mc = lines[idx]?.materialCode;
    updateLine(idx, { unitPrice });
    onLineFieldErrorChange?.(idx, 'unitPrice', unitPrice, mc);
  };

  return (
    <>
      <div className={df.tableWrapper}>
        <table className={[df.linesTable, df.linesTableStacked].join(' ')}>
          <colgroup>
            <col className={df.linesColMatCode} />
            <col className={df.linesColMatName} />
            <col className={df.linesColQty} />
            <col className={df.linesColUnitPrice} />
            <col />
            <col className={df.linesColTax} />
            <col className={df.linesColAmount} />
            <col className={df.linesColAmount} />
            <col className={df.linesColDel} />
          </colgroup>
          <thead>
            <tr>
              <MaterialLineTableHeaders />
              <th className={df.thAmount}>SL</th>
              <th className={df.thAmount}>Đơn giá</th>
              <th className={df.thDiscount}>Giảm giá</th>
              <th className={df.thAmount}>% Thuế</th>
              <th className={df.thAmount}>Tiền thuế</th>
              <th className={df.thAmount}>Thành tiền</th>
              <th className={df.thDel} />
            </tr>
          </thead>
          <tbody>
            {lines.map((line, idx) => {
              const rowErr = lineErrors?.[idx];
              return (
                <tr key={idx} data-testid={tid(`line-${idx}`)} {...lineRowProps(idx)}>
                  <LineMaterialSearchCell
                    materialCode={line.materialCode}
                    materialName={line.materialName ?? ''}
                    error={rowErr?.materialCode}
                    disabled={!canEdit}
                    onSelect={m => handleMaterialSelect(idx, m)}
                    onClear={() => handleMaterialClear(idx)}
                  />
                  <td data-label="SL" className={df.tdAmount}>
                    <NumberInput
                      id={tid(`line-${idx}-quantity`)}
                      value={line.quantity}
                      error={rowErr?.quantity}
                      onChange={makeQuantityChange(idx)}
                      disabled={!canEdit}
                      data-testid={tid(`line-${idx}-quantity`)}
                    />
                  </td>
                  <td data-label="Đơn giá" className={df.tdAmount}>
                    <MoneyInput
                      id={tid(`line-${idx}-unitPrice`)}
                      value={line.unitPrice}
                      error={rowErr?.unitPrice}
                      onChange={makeUnitPriceChange(idx)}
                      disabled={!canEdit}
                      data-testid={tid(`line-${idx}-unitPrice`)}
                    />
                  </td>
                  <td data-label="Giảm giá" className={df.tdAmount}>
                    <InvoiceLineDiscountPair
                      line={line}
                      lineIndex={idx}
                      canEdit={canEdit}
                      onDiscountRateChange={discountRate => updateLine(idx, { discountRate })}
                      onDiscountAmountChange={discountAmount =>
                        updateLine(idx, { discountRate: 0, discountAmount })}
                    />
                  </td>
                  <td data-label="% Thuế" className={df.tdAmount}>
                    <NumberInput
                      value={line.taxRate}
                      onChange={taxRate => updateLine(idx, { taxRate })}
                      disabled={!canEdit}
                      format={{ maxDecimals: 2, thousandSeparator: ' ', decimalSeparator: ',' }}
                      data-testid={tid(`line-${idx}-taxRate`)}
                    />
                  </td>
                  <td data-label="Tiền thuế" className={[df.tdAmount, DS_TEXT_END_CLASS].join(' ')}>
                    <LabelMoney
                      layout="value"
                      variant="cell"
                      value={line.taxAmount}
                      data-testid={tid(`line-${idx}-taxAmount`)}
                    />
                  </td>
                  <td data-label="Thành tiền" className={[df.tdAmount, DS_TEXT_END_CLASS].join(' ')}>
                    <LabelMoney
                      layout="value"
                      variant="cell"
                      value={line.amount}
                      data-testid={tid(`line-${idx}-amount`)}
                    />
                  </td>
                  <td className={df.tdDel} data-label="">
                    <button
                      type="button"
                      className={df.btnDeleteLine}
                      onClick={() => onRemoveLine(idx)}
                      title="Xóa dòng"
                      disabled={!canEdit}
                    >
                      ×
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
      <MaterialLinesGridActions
        canEdit={canEdit}
        onAddLine={onAddLine}
        onCopyLine={onCopyLine}
        linesCount={lines.length}
        testIdPrefix={testIdPrefix}
      />
    </>
  );
};
