import React from 'react';
import df from '../../styles/documentForm.module.css';

export type MaterialLinesGridActionsProps = {
  canEdit: boolean;
  onAddLine: () => void;
  onCopyLine: () => void;
  linesCount: number;
  testIdPrefix?: string;
};

export const MaterialLinesGridActions: React.FC<MaterialLinesGridActionsProps> = ({
  canEdit,
  onAddLine,
  onCopyLine,
  linesCount,
  testIdPrefix = 'hoa-don',
}) => {
  if (!canEdit) return null;
  const tid = (suffix: string) => `${testIdPrefix}-${suffix}`;
  return (
    <div className={df.linesActions}>
      <button
        type="button"
        className={df.btnAddLine}
        onClick={onAddLine}
        data-testid={tid('add-line-btn')}
      >
        + Thêm dòng
      </button>
      <button
        type="button"
        className={df.btnCopyLine}
        onClick={onCopyLine}
        disabled={linesCount === 0}
        data-testid={tid('copy-line-btn')}
      >
        Sao chép dòng
      </button>
    </div>
  );
};
